mapper.sql:
WHERE m.branch_seq = #{branchSeq}

    AND (m.name LIKE CONCAT('%', #{keyword}, '%')
      OR m.phone_number LIKE CONCAT('%', #{keyword}, '%'))

mapper.select:
SELECT sub.memberSeq, sub.status FROM ( SELECT a.member_seq AS memberSeq, CASE a.status WHEN '출석' THEN 'O' WHEN '연기' THEN '△' ELSE 'X' END AS status, ROW_NUMBER() OVER (PARTITION BY a.member_seq ORDER BY a.attendance_date DESC) AS rn FROM complex_member_attendance a WHERE a.member_seq IN
#{seq}
) sub WHERE sub.rn <= 14 ORDER BY sub.memberSeq, sub.rn
